exercises.solution:
const cache = new WeakMap();
const counter = { hits: 0, misses: 0 };

function compute(obj) {
  if (cache.has(obj)) {
    counter.hits++;
    console.log('Cache hit');
    return cache.get(obj);
  }
  counter.misses++;
  console.log('Cache miss');
  const sum = Object.values(obj).reduce((acc, val) => acc + val, 0);
  cache.set(obj, sum);
  return sum;
}

const data1 = { a: 10, b: 20, c: 30 };
const data2 = { x: 5, y: 15 };

console.log('Result:', compute(data1));
console.log('Result:', compute(data1));
console.log('Result:', compute(data2));
console.log('Stats:', counter);

